INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSBSAGYBM5SHGEHY10X','site_config','01KRECGSSABW0X1GXJCWVWYTKN','{"phone":"(844) 442-4222","address_line1":"201 Believe Lane, Suite B","address_line2":"","city_state":"Georgetown, KY 40324","email":"info@commonwealthaudiology.com","book_url":"#book","hero_heading":"Compassionate hearing care that feels like home.","hero_subtext":"Hearing care you can trust, for every stage of life.","about_tagline":"AUDIOLOGY EXCELLENCE & PATIENT CARE","about_heading":"Commonwealth Audiology","about_text":"Life is full of meaningful sounds: laughter with loved ones, conversations with friends, music you love, and the world sounds all around you. When this changes, it can feel isolating, but we''re here to help. At Commonwealth Audiology, your hearing wellness is our top priority. Every recommendation we make is shaped by what functions for your specific lifestyle needs and the life you love to live. Our Doctor of Audiology, Dr. Tiffany Brown, stays up to date with the latest hearing technology to ensure you receive the most effective and innovative care available.","team_heading":"Meet Your Local Hearing Professionals","team_text":"At Commonwealth Audiology, our focus is on restoring clarity, comfort, and confidence so you can fully participate in the world around you. With superior guidance, clinical excellence, and care centered on you, we partner with our patients and their families each and every day.","hours_mon":"9:00am - 5:00pm","hours_tue":"9:00am - 5:00pm","hours_wed":"9:00am - 5:00pm","hours_thu":"9:00am - 5:00pm","hours_fri":"9:00am - 5:00pm","hours_sat":"9:00am - 1:00pm","hours_sun":"Closed","map_embed_url":"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3134!2d-84.5603!3d38.2098!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2zMzjCsDEyJzM1LjMiTiA4NMKwMzMnMzcuMSJX!5e0!3m2!1sen!2sus!4v1234567890","services_heading":"Audiology Services in Georgetown, KY","services_subtext":"At Commonwealth Audiology, we provide hearing care to meet your every need. It''s our commitment to make sure you can hear every moment clearly.","hearing_aids_heading":"Hearing Aids & Hearing Aid Services","hearing_aids_subtext":"We provide best-in-class hearing aid solutions with expert fittings, adjustments, repairs, and ongoing maintenance so you can hear your best every day.","protection_heading":"Hearing Protection Solutions in Georgetown, KY","protection_subtext":"For anyone exposed to loud noise, custom ear protection offers the safest and most comfortable way to preserve your hearing.","testimonials_heading":"What Our Patients Are Saying","faq_heading":"Frequently Asked Questions","news_heading":"News & Articles","footer_tagline":"Compassionate hearing care in Georgetown, KY. Helping you hear every meaningful moment of life."}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSCHD2PK5YX3YMM0DBQ','services','01KRECGSSC525JMB3SR8Q4A7EJ','{"title":"Hearing Evaluations","description":"A comprehensive hearing evaluation is the first step toward better hearing. Our Doctor of Audiology will assess your hearing health using the latest diagnostic tools and techniques.","link_url":"/audiology-services/hearing-tests/","sort_order":"1"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSDAHFTKJM8KND2HDP5','services','01KRECGSSDMCPC3R5NSN7QH29M','{"title":"Hearing Loss Evaluation & Treatment","description":"We work together to understand what you are experiencing and recommend treatment options tailored to your specific type and degree of hearing loss with confidence.","link_url":"/audiology-services/sensorineural-hearing-loss/","sort_order":"2"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSEP6FBDG86QC6JVJ29','services','01KRECGSSDYW50R55451B9S1M5','{"title":"Ear Wax Removal","description":"Excess earwax can sometimes accumulate and cause hearing loss. Our safe, professional ear wax removal services restore your hearing clarity quickly and comfortably.","link_url":"/audiology-services/ear-wax-removal/","sort_order":"3"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSFQP25GP5N5EDTZC23','services','01KRECGSSE6FDTVVNN2G7ETG6R','{"title":"Tinnitus Evaluations & Treatment","description":"Ringing, buzzing, or whooshing in the ears can be stressful. We fully evaluate your tinnitus and discuss various treatment options designed to find what works best for you.","link_url":"/audiology-services/tinnitus-evaluation-treatment/","sort_order":"4"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSFQP25GP5N5EDTZC24','hearing_aids','01KRECGSSFBS2ZY34FVYJQM76R','{"title":"Hearing Aid Selection","description":"We offer a full line of hearing aid styles, including completely-in-canal and Bluetooth-compatible models, allowing you to select the style that fits your budget, lifestyle, and hearing needs.","link_url":"/audiology-services/hearing-aid-services/","sort_order":"1"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSGSMJQER96Q44SVHV1','hearing_aids','01KRECGSSGT4D3PR3MWE3WM268','{"title":"Hearing Aid Fittings","description":"We take great care with precise new adjustments, using real-ear measurement to ensure you can be confident and comfortable with your hearing aids in any situation.","link_url":"/audiology-services/hearing-aid-fittings/","sort_order":"2"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSGSMJQER96Q44SVHV2','hearing_aids','01KRECGSSG6NJSNWQH3SD410T6','{"title":"Hearing Aid Cleaning & Repair","description":"We provide cleaning, troubleshooting, and simple repairs so your devices work as comfortably and as well as the day you received them, getting you back to better hearing fast.","link_url":"/audiology-services/hearing-aid-services/","sort_order":"3"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSHE8P88Z79R799KKJG','hearing_aids','01KRECGSSHNN4CYY7HD94XB044','{"title":"Hearing Aid Batteries & Accessories","description":"We carry a variety of batteries, chargers, cleaning tools, and accessories to keep your hearing devices running and sounding their very best.","link_url":"/hearing-aids-products/hearing-aid-batteries/","sort_order":"4"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSHE8P88Z79R799KKJH','team','01KRECGSSH782F4QYXR5AT73ZD','{"name":"Dr. Tiffany Brown","role":"Doctor of Audiology","bio":"Dr. Tiffany Brown is committed to providing personalized, compassionate hearing care to every patient.","sort_order":"1"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSJ1FMXF2WK70WTJA06','team','01KRECGSSJX5MDF7EH29X81WJ9','{"name":"Ashley Gogols","role":"Hearing Instrument Specialist","bio":"Ashley is dedicated to helping patients find the right hearing solutions for their unique lifestyle.","sort_order":"2"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSK4GK5ZEGP4FRXF302','testimonials','01KRECGSSJPY3HMQRZM1FXAYCF','{"patient_name":"Laci Wills","rating":"5","review":"Absolutely love this place! The staff is so friendly and helpful. My hearing aids have changed my life and I couldn''t be more grateful!","sort_order":"1"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSK4GK5ZEGP4FRXF303','testimonials','01KRECGSSKWDMMDZTX9AJF9P6K','{"patient_name":"Tracy Davis","rating":"5","review":"Professional, knowledgeable, and kind. The whole team made me feel comfortable from the moment I walked in. Highly recommend Commonwealth Audiology!","sort_order":"2"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSRNWKX1EDEFF0EA3MC','testimonials','01KRECGSSR7QP4Z02NYJY8G5FC','{"patient_name":"Ola Mack","rating":"5","review":"Great experience from start to finish. Dr. Brown took the time to really listen and find the perfect solution for me. Outstanding care!","sort_order":"3"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSSK2GBBBJ4Z1MMF9VF','testimonials','01KRECGSSSGJVK9HDZAQEYZNAX','{"patient_name":"Garrett Hanover","rating":"5","review":"I was nervous about getting hearing aids, but the team here made the whole process easy and stress-free. Amazing patient care!","sort_order":"4"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSSK2GBBBJ4Z1MMF9VG','testimonials','01KRECGSSS7JRXZB07CR4Q8KP1','{"patient_name":"Audra Rugg","rating":"5","review":"Commonwealth Audiology exceeded all my expectations. The care is professional, the staff are wonderful, and I can finally hear again!","sort_order":"5"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSTCHZF7WSC18XFTQVT','faq','01KRECGSSTRGD9WAKSV3PMACW7','{"question":"How do I know if I need a hearing aid?","answer":"If you frequently ask people to repeat themselves, have difficulty hearing in noisy environments, or find yourself turning up the TV volume, it may be time for a hearing evaluation. Schedule an appointment with our audiologist for a comprehensive assessment.","sort_order":"1"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSTCHZF7WSC18XFTQVV','faq','01KRECGSST5YJ1DZJT9K66EEFZ','{"question":"Are hearing aids covered by insurance?","answer":"Coverage varies by insurance plan. Many plans offer partial coverage for hearing aids. Our team can help you understand your benefits and explore financing options to make hearing care accessible for you.","sort_order":"2"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSVZ2G2KNCG2GNX50B4','faq','01KRECGSSVMSNQCQDTCVJBJJKS','{"question":"How often should I get a hearing test?","answer":"Adults should have their hearing tested every 3-5 years, or more frequently if you notice changes. Those with existing hearing loss or high noise exposure should be tested annually.","sort_order":"3"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSVZ2G2KNCG2GNX50B5','faq','01KRECGSSVSD477EYTXKJ81T35','{"question":"Can I get a hearing aid without a fitting?","answer":"A professional fitting is essential for optimal hearing aid performance. Proper fitting ensures the device is programmed correctly for your specific hearing loss, fits comfortably, and delivers the best possible sound quality.","sort_order":"4"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSWYDFVZXGMVR82WJ15','faq','01KRECGSSW68AGNJZC8Y8DBH3H','{"question":"How can hearing aids help with tinnitus?","answer":"Many modern hearing aids include tinnitus masking features that produce soothing sounds to reduce the perception of ringing. Combined with hearing amplification, they can significantly improve quality of life for tinnitus sufferers.","sort_order":"5"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSWYDFVZXGMVR82WJ16','hearing_protection','01KRECGSSW1KHJQFYZMS3B1MGF','{"title":"Custom Hearing Protection & Ear Molds","description":"Our custom ear solutions reduce harmful sounds while keeping important sounds audible, so you can work safely and enjoy what you love without fear of hearing damage.","sort_order":"1"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSWYDFVZXGMVR82WJ17','hearing_protection','01KRECGSSW0TT2ZG305JDWY3S6','{"title":"Hearing Protection for Musicians","description":"Musicians are at high risk for regular exposure to loud volumes that can harm their hearing. We provide specially designed protection that lets you enjoy music you love while preserving your hearing for years to come.","sort_order":"2"}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGSSXTP9W660RTK39B20J','hearing_protection','01KRECGSSXMXM1XA37MH9SN4JA','{"title":"Hearing Protection for Hunters","description":"Sudden, loud blasts from firearms can cause severe, permanent hearing damage. Our custom hunter''s ear protection provides incredible ambient sound awareness while protecting your hearing from dangerous impulse noise.","sort_order":"3"}',NULL,'2026-05-12 15:22:36');
