INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGST03NC7WK5ACCHE5BNT','pages','01KRECGST0WGFTFE5YCEVFV7XD','{"title":"About Commonwealth Audiology","content":[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Commonwealth Audiology is a leading audiology practice in Georgetown, KY, dedicated to providing compassionate, personalized hearing care to patients of all ages."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Our Doctor of Audiology, Dr. Tiffany Brown, stays up to date with the latest hearing technology to ensure you receive the most effective and innovative care available."}]}]}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGTBY4SA47XD3MBME0EV6','posts','01KRECGTBTBWTA59MA9GT0HQQV','{"title":"5 Signs You May Need a Hearing Test","featured_image":{"provider":"local","id":"01KRECGT8FHAGCKCY2A2KNFWYQ","alt":"Audiologist performing a hearing test","width":1200,"height":800,"mimeType":"image/jpeg","filename":"hearing-test-signs.jpg","meta":{"storageKey":"01KRECGT8FHAGCKCY2A2KNFWYQ.jpg"}},"content":[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Hearing loss often develops so gradually that many people don''t notice it until it begins significantly affecting their daily life. Knowing the warning signs can help you seek care before the problem worsens."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"1. Asking people to repeat themselves"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"If you frequently ask friends, family, or coworkers to repeat what they''ve said, this is one of the most common early signs of hearing loss. It may be happening more than you realize."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"2. Difficulty hearing in noisy environments"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Struggling to follow conversations in restaurants, social gatherings, or other noisy places is a hallmark sign of hearing difficulty. Background noise can be especially challenging for people with hearing loss."}]}],"excerpt":"Hearing loss often develops gradually. Here are the key signs to watch for and when to schedule your evaluation."}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGTH7P1SQ019Q50ZGBT2N','posts','01KRECGTH6FE0Z2FDYN50PPWGQ','{"title":"How Modern Hearing Aid Technology Has Changed Lives","featured_image":{"provider":"local","id":"01KRECGTFEVXATK58EDERYPYBV","alt":"Modern hearing aid technology","width":1200,"height":800,"mimeType":"image/jpeg","filename":"hearing-aid-technology.jpg","meta":{"storageKey":"01KRECGTFEVXATK58EDERYPYBV.jpg"}},"content":[{"_type":"block","style":"normal","children":[{"_type":"span","text":"The hearing aids of today bear little resemblance to the bulky, whistling devices of decades past. Modern hearing aids are sleek, nearly invisible, and packed with technology that adapts to your environment in real time."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Bluetooth connectivity"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Most modern hearing aids can connect directly to smartphones, TVs, and other Bluetooth devices. This means you can stream phone calls, music, and audio directly to your hearing aids."}]}],"excerpt":"Today''s hearing aids are more advanced than ever — smaller, smarter, and connected. Here''s what you need to know."}',NULL,'2026-05-12 15:22:36');
INSERT INTO "revisions" ("id","collection","entry_id","data","author_id","created_at") VALUES ('01KRECGTP6PSJ8N2W7WJ9GSSRM','posts','01KRECGTP517Z017G883W7C9E6','{"title":"Tinnitus: Causes, Symptoms, and Treatment Options","featured_image":{"provider":"local","id":"01KRECGTMYFF09HQVX6SY3M31E","alt":"Person experiencing tinnitus","width":1200,"height":800,"mimeType":"image/jpeg","filename":"tinnitus-treatment.jpg","meta":{"storageKey":"01KRECGTMYFF09HQVX6SY3M31E.jpg"}},"content":[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Tinnitus — the perception of ringing, buzzing, hissing, or other sounds in the ears — affects an estimated 50 million Americans. While it can be distressing, many effective management strategies are available."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Common causes of tinnitus"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Tinnitus can be caused by noise-induced hearing loss, age-related hearing loss, ear infections, earwax blockage, certain medications, or other medical conditions. Identifying the underlying cause is the first step to effective treatment."}]}],"excerpt":"Ringing in the ears affects millions of Americans. Learn what causes tinnitus and how it can be treated."}',NULL,'2026-05-12 15:22:37');
