INSERT INTO "ec_testimonials" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","patient_name","rating","review","avatar","sort_order") VALUES ('01KRECGSSJPY3HMQRZM1FXAYCF','testimonial-laci-wills','published',NULL,NULL,'2026-05-12T15:22:36.211Z','2026-05-12T15:22:36.211Z','2026-05-12T15:22:36.210Z',NULL,NULL,1,'01KRECGSSK4GK5ZEGP4FRXF302',NULL,'en','01KRECGSSJPY3HMQRZM1FXAYCF','Laci Wills','5','Absolutely love this place! The staff is so friendly and helpful. My hearing aids have changed my life and I couldn''t be more grateful!',NULL,'1');
INSERT INTO "ec_testimonials" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","patient_name","rating","review","avatar","sort_order") VALUES ('01KRECGSSKWDMMDZTX9AJF9P6K','testimonial-tracy-davis','published',NULL,NULL,'2026-05-12T15:22:36.211Z','2026-05-12T15:22:36.211Z','2026-05-12T15:22:36.211Z',NULL,NULL,1,'01KRECGSSK4GK5ZEGP4FRXF303',NULL,'en','01KRECGSSKWDMMDZTX9AJF9P6K','Tracy Davis','5','Professional, knowledgeable, and kind. The whole team made me feel comfortable from the moment I walked in. Highly recommend Commonwealth Audiology!',NULL,'2');
INSERT INTO "ec_testimonials" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","patient_name","rating","review","avatar","sort_order") VALUES ('01KRECGSSR7QP4Z02NYJY8G5FC','testimonial-ola-mack','published',NULL,NULL,'2026-05-12T15:22:36.216Z','2026-05-12T15:22:36.216Z','2026-05-12T15:22:36.216Z',NULL,NULL,1,'01KRECGSSRNWKX1EDEFF0EA3MC',NULL,'en','01KRECGSSR7QP4Z02NYJY8G5FC','Ola Mack','5','Great experience from start to finish. Dr. Brown took the time to really listen and find the perfect solution for me. Outstanding care!',NULL,'3');
INSERT INTO "ec_testimonials" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","patient_name","rating","review","avatar","sort_order") VALUES ('01KRECGSSSGJVK9HDZAQEYZNAX','testimonial-garrett-hanover','published',NULL,NULL,'2026-05-12T15:22:36.217Z','2026-05-12T15:22:36.217Z','2026-05-12T15:22:36.217Z',NULL,NULL,1,'01KRECGSSSK2GBBBJ4Z1MMF9VF',NULL,'en','01KRECGSSSGJVK9HDZAQEYZNAX','Garrett Hanover','5','I was nervous about getting hearing aids, but the team here made the whole process easy and stress-free. Amazing patient care!',NULL,'4');
INSERT INTO "ec_testimonials" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","patient_name","rating","review","avatar","sort_order") VALUES ('01KRECGSSS7JRXZB07CR4Q8KP1','testimonial-audra-rugg','published',NULL,NULL,'2026-05-12T15:22:36.217Z','2026-05-12T15:22:36.217Z','2026-05-12T15:22:36.217Z',NULL,NULL,1,'01KRECGSSSK2GBBBJ4Z1MMF9VG',NULL,'en','01KRECGSSS7JRXZB07CR4Q8KP1','Audra Rugg','5','Commonwealth Audiology exceeded all my expectations. The care is professional, the staff are wonderful, and I can finally hear again!',NULL,'5');
INSERT INTO "ec_faq" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","question","answer","sort_order") VALUES ('01KRECGSSTRGD9WAKSV3PMACW7','how-do-i-know-if-i-need-hearing-aid','published',NULL,NULL,'2026-05-12T15:22:36.218Z','2026-05-12T15:22:36.218Z','2026-05-12T15:22:36.218Z',NULL,NULL,1,'01KRECGSSTCHZF7WSC18XFTQVT',NULL,'en','01KRECGSSTRGD9WAKSV3PMACW7','How do I know if I need a hearing aid?','If you frequently ask people to repeat themselves, have difficulty hearing in noisy environments, or find yourself turning up the TV volume, it may be time for a hearing evaluation. Schedule an appointment with our audiologist for a comprehensive assessment.','1');
INSERT INTO "ec_faq" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","question","answer","sort_order") VALUES ('01KRECGSST5YJ1DZJT9K66EEFZ','are-hearing-aids-covered-by-insurance','published',NULL,NULL,'2026-05-12T15:22:36.218Z','2026-05-12T15:22:36.218Z','2026-05-12T15:22:36.218Z',NULL,NULL,1,'01KRECGSSTCHZF7WSC18XFTQVV',NULL,'en','01KRECGSST5YJ1DZJT9K66EEFZ','Are hearing aids covered by insurance?','Coverage varies by insurance plan. Many plans offer partial coverage for hearing aids. Our team can help you understand your benefits and explore financing options to make hearing care accessible for you.','2');
INSERT INTO "ec_faq" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","question","answer","sort_order") VALUES ('01KRECGSSVMSNQCQDTCVJBJJKS','how-often-should-i-get-hearing-test','published',NULL,NULL,'2026-05-12T15:22:36.219Z','2026-05-12T15:22:36.219Z','2026-05-12T15:22:36.219Z',NULL,NULL,1,'01KRECGSSVZ2G2KNCG2GNX50B4',NULL,'en','01KRECGSSVMSNQCQDTCVJBJJKS','How often should I get a hearing test?','Adults should have their hearing tested every 3-5 years, or more frequently if you notice changes. Those with existing hearing loss or high noise exposure should be tested annually.','3');
INSERT INTO "ec_faq" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","question","answer","sort_order") VALUES ('01KRECGSSVSD477EYTXKJ81T35','can-i-get-hearing-aid-without-fitting','published',NULL,NULL,'2026-05-12T15:22:36.219Z','2026-05-12T15:22:36.219Z','2026-05-12T15:22:36.219Z',NULL,NULL,1,'01KRECGSSVZ2G2KNCG2GNX50B5',NULL,'en','01KRECGSSVSD477EYTXKJ81T35','Can I get a hearing aid without a fitting?','A professional fitting is essential for optimal hearing aid performance. Proper fitting ensures the device is programmed correctly for your specific hearing loss, fits comfortably, and delivers the best possible sound quality.','4');
INSERT INTO "ec_faq" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","question","answer","sort_order") VALUES ('01KRECGSSW68AGNJZC8Y8DBH3H','how-can-hearing-aids-help-with-tinnitus','published',NULL,NULL,'2026-05-12T15:22:36.220Z','2026-05-12T15:22:36.220Z','2026-05-12T15:22:36.220Z',NULL,NULL,1,'01KRECGSSWYDFVZXGMVR82WJ15',NULL,'en','01KRECGSSW68AGNJZC8Y8DBH3H','How can hearing aids help with tinnitus?','Many modern hearing aids include tinnitus masking features that produce soothing sounds to reduce the perception of ringing. Combined with hearing amplification, they can significantly improve quality of life for tinnitus sufferers.','5');
INSERT INTO "ec_hearing_protection" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","description","sort_order") VALUES ('01KRECGSSW1KHJQFYZMS3B1MGF','custom-hearing-protection','published',NULL,NULL,'2026-05-12T15:22:36.220Z','2026-05-12T15:22:36.220Z','2026-05-12T15:22:36.220Z',NULL,NULL,1,'01KRECGSSWYDFVZXGMVR82WJ16',NULL,'en','01KRECGSSW1KHJQFYZMS3B1MGF','Custom Hearing Protection & Ear Molds','Our custom ear solutions reduce harmful sounds while keeping important sounds audible, so you can work safely and enjoy what you love without fear of hearing damage.','1');
INSERT INTO "ec_hearing_protection" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","description","sort_order") VALUES ('01KRECGSSW0TT2ZG305JDWY3S6','hearing-protection-musicians','published',NULL,NULL,'2026-05-12T15:22:36.220Z','2026-05-12T15:22:36.220Z','2026-05-12T15:22:36.220Z',NULL,NULL,1,'01KRECGSSWYDFVZXGMVR82WJ17',NULL,'en','01KRECGSSW0TT2ZG305JDWY3S6','Hearing Protection for Musicians','Musicians are at high risk for regular exposure to loud volumes that can harm their hearing. We provide specially designed protection that lets you enjoy music you love while preserving your hearing for years to come.','2');
INSERT INTO "ec_hearing_protection" ("id","slug","status","author_id","primary_byline_id","created_at","updated_at","published_at","scheduled_at","deleted_at","version","live_revision_id","draft_revision_id","locale","translation_group","title","description","sort_order") VALUES ('01KRECGSSXMXM1XA37MH9SN4JA','hearing-protection-hunters','published',NULL,NULL,'2026-05-12T15:22:36.221Z','2026-05-12T15:22:36.221Z','2026-05-12T15:22:36.221Z',NULL,NULL,1,'01KRECGSSXTP9W660RTK39B20J',NULL,'en','01KRECGSSXMXM1XA37MH9SN4JA','Hearing Protection for Hunters','Sudden, loud blasts from firearms can cause severe, permanent hearing damage. Our custom hunter''s ear protection provides incredible ambient sound awareness while protecting your hearing from dangerous impulse noise.','3');
