CREATE VIRTUAL TABLE "_emdash_fts_posts" USING fts5(
				id UNINDEXED, locale UNINDEXED, title, content,
				content='ec_posts',
				content_rowid='rowid',
				tokenize='porter unicode61'
			);
CREATE VIRTUAL TABLE "_emdash_fts_pages" USING fts5(
				id UNINDEXED, locale UNINDEXED, title, content,
				content='ec_pages',
				content_rowid='rowid',
				tokenize='porter unicode61'
			);
INSERT INTO "_emdash_fts_posts"("_emdash_fts_posts") VALUES('rebuild');
INSERT INTO "_emdash_fts_pages"("_emdash_fts_pages") VALUES('rebuild');
CREATE TRIGGER "_emdash_fts_pages_insert" 
			AFTER INSERT ON "ec_pages" 
			WHEN NEW.deleted_at IS NULL
			BEGIN
				INSERT INTO "_emdash_fts_pages"(rowid, id, locale, title, content)
				VALUES (NEW.rowid, NEW.id, NEW.locale, NEW.title, NEW.content);
			END;
CREATE TRIGGER "_emdash_fts_pages_update" 
			AFTER UPDATE ON "ec_pages" 
			BEGIN
				DELETE FROM "_emdash_fts_pages" WHERE rowid = OLD.rowid;
				INSERT INTO "_emdash_fts_pages"(rowid, id, locale, title, content)
				SELECT NEW.rowid, NEW.id, NEW.locale, NEW.title, NEW.content
				WHERE NEW.deleted_at IS NULL;
			END;
CREATE TRIGGER "_emdash_fts_pages_delete" 
			AFTER DELETE ON "ec_pages" 
			BEGIN
				DELETE FROM "_emdash_fts_pages" WHERE rowid = OLD.rowid;
			END;
CREATE TRIGGER "_emdash_fts_posts_insert" AFTER INSERT ON "ec_posts" WHEN NEW.deleted_at IS NULL BEGIN INSERT INTO "_emdash_fts_posts"(rowid,id,locale,title,content) VALUES (NEW.rowid,NEW.id,NEW.locale,NEW.title,NEW.content); END;
CREATE TRIGGER "_emdash_fts_posts_update" AFTER UPDATE ON "ec_posts" BEGIN DELETE FROM "_emdash_fts_posts" WHERE rowid=OLD.rowid; INSERT INTO "_emdash_fts_posts"(rowid,id,locale,title,content) SELECT NEW.rowid,NEW.id,NEW.locale,NEW.title,NEW.content WHERE NEW.deleted_at IS NULL; END;
CREATE TRIGGER "_emdash_fts_posts_delete" AFTER DELETE ON "ec_posts" BEGIN DELETE FROM "_emdash_fts_posts" WHERE rowid=OLD.rowid; END;
